static const char* GetNxExceptionMessage(const exception& ex)
{
	const NXOpen::NXException* nxException = dynamic_cast<const NXOpen::NXException*>(&ex);
	if (nxException != NULL)
	{
		return nxException->Message();
	}
	return ex.what();
}

static NXOpen::Body* GetCurveParentBody(NXOpen::Drawings::DraftingCurve* draftingCurve)
{
	if (draftingCurve == NULL)
	{
		return NULL;
	}

	std::vector<NXOpen::NXObject*> parents = draftingCurve->GetDraftingCurveInfo()->GetParents();
	for (size_t i = 0; i < parents.size(); i++)
	{
		if (parents[i] == NULL)
		{
			continue;
		}

		int type = 0;
		int subtype = 0;
		UF_OBJ_ask_type_and_subtype(parents[i]->Tag(), &type, &subtype);
		if (subtype == UF_solid_face_subtype)
		{
			NXOpen::Face* face = dynamic_cast<NXOpen::Face*>(NXOpen::NXObjectManager::Get(parents[i]->Tag()));
			return face == NULL ? NULL : face->GetBody();
		}
		if (subtype == UF_solid_edge_subtype)
		{
			NXOpen::Edge* edge = dynamic_cast<NXOpen::Edge*>(NXOpen::NXObjectManager::Get(parents[i]->Tag()));
			return edge == NULL ? NULL : edge->GetBody();
		}
	}
	return NULL;
}

static NXOpen::Drawings::DraftingBody* FindDraftingBodyForModelBody(NXOpen::Drawings::DraftingView* draftingView, NXOpen::Body* modelBody)
{
	if (draftingView == NULL || modelBody == NULL)
	{
		return NULL;
	}

	NXOpen::Drawings::DraftingBodyCollection* bodyCollection = draftingView->DraftingBodies();
	for (NXOpen::Drawings::DraftingBodyCollection::iterator it = bodyCollection->begin(); it != bodyCollection->end(); ++it)
	{
		NXOpen::Drawings::DraftingBody* draftingBody = (*it);
		if (draftingBody == NULL)
		{
			continue;
		}

		NXOpen::Drawings::DraftingCurveCollection* curveCollection = draftingBody->DraftingCurves();
		for (NXOpen::Drawings::DraftingCurveCollection::iterator curveIt = curveCollection->begin(); curveIt != curveCollection->end(); ++curveIt)
		{
			if (GetCurveParentBody(*curveIt) == modelBody)
			{
				return draftingBody;
			}
		}
	}
	return NULL;
}

static std::vector<NXOpen::Drawings::DraftingCurve*> CollectDraftingCurves(NXOpen::Drawings::DraftingBody* draftingBody)
{
	std::vector<NXOpen::Drawings::DraftingCurve*> curves;
	if (draftingBody == NULL)
	{
		return curves;
	}

	NXOpen::Drawings::DraftingCurveCollection* curveCollection = draftingBody->DraftingCurves();
	for (NXOpen::Drawings::DraftingCurveCollection::iterator it = curveCollection->begin(); it != curveCollection->end(); ++it)
	{
		if ((*it) != NULL)
		{
			curves.push_back(*it);
		}
	}
	return curves;
}

static double AskBodyDrawingArea(tag_t viewTag, NXOpen::Body* body)
{
	if (body == NULL)
	{
		return 0.0;
	}

	bool hasPoint = false;
	double minX = 0.0, minY = 0.0, maxX = 0.0, maxY = 0.0;
	std::vector<NXOpen::Face*> faces = body->GetFaces();
	for (size_t i = 0; i < faces.size(); i++)
	{
		std::vector<NXOpen::Edge*> edges = faces[i]->GetEdges();
		for (size_t j = 0; j < edges.size(); j++)
		{
			NXOpen::Point3d startPoint;
			NXOpen::Point3d endPoint;
			edges[j]->GetVertices(&startPoint, &endPoint);
			double modelPoints[2][3] =
			{
				{ startPoint.X, startPoint.Y, startPoint.Z },
				{ endPoint.X, endPoint.Y, endPoint.Z }
			};

			for (int p = 0; p < 2; p++)
			{
				double drawingPoint[2];
				if (UF_VIEW_map_model_to_drawing(viewTag, modelPoints[p], drawingPoint) != 0)
				{
					continue;
				}
				if (!hasPoint)
				{
					minX = maxX = drawingPoint[0];
					minY = maxY = drawingPoint[1];
					hasPoint = true;
				}
				else
				{
					if (drawingPoint[0] < minX) minX = drawingPoint[0];
					if (drawingPoint[0] > maxX) maxX = drawingPoint[0];
					if (drawingPoint[1] < minY) minY = drawingPoint[1];
					if (drawingPoint[1] > maxY) maxY = drawingPoint[1];
				}
			}
		}
	}
	return hasPoint ? fabs((maxX - minX) * (maxY - minY)) : 0.0;
}

static bool BodyHasSmallBendRadius(NXOpen::Body* body)
{
	if (body == NULL)
	{
		return false;
	}

	std::vector<NXOpen::Face*> faces = body->GetFaces();
	for (size_t i = 0; i < faces.size(); i++)
	{
		int type1 = 0;
		double point[3], dir[3], box[6], radius = 0.0, rad_data = 0.0;
		int norm_dir = 0;
		UF_MODL_ask_face_data(faces[i]->Tag(), &type1, point, dir, box, &radius, &rad_data, &norm_dir);
		if (fabs(radius - 0.2) < 0.01)
		{
			return true;
		}
	}
	return false;
}

static bool IsBodyDisplayed(NXOpen::Body* body)
{
	if (body == NULL)
	{
		return false;
	}

	UF_OBJ_disp_props_s disp_props;
	int layer_status = 0;
	UF_OBJ_ask_display_properties(body->Tag(), &disp_props);
	UF_LAYER_ask_status(disp_props.layer, &layer_status);
	return disp_props.blank_status == UF_OBJ_NOT_BLANKED &&
		(layer_status == UF_LAYER_WORK_LAYER || layer_status == UF_LAYER_ACTIVE_LAYER);
}

static double MeasureMinimumDistance(NXOpen::Part* part, NXOpen::DisplayableObject* firstObject, NXOpen::DisplayableObject* secondObject)
{
	if (part == NULL || firstObject == NULL || secondObject == NULL)
	{
		return 999999.0;
	}

	NXOpen::MeasureDistance* measureDistance =
		part->MeasureManager()->NewDistance(NULL, NXOpen::MeasureManager::MeasureTypeMinimum, firstObject, secondObject);
	return measureDistance == NULL ? 999999.0 : measureDistance->Value();
}

static bool AreModelPointsCoincidentInDrawing(NXOpen::Drawings::BaseView* baseView, const double firstPoint[3], const double secondPoint[3], double tolerance)
{
	if (baseView == NULL || firstPoint == NULL || secondPoint == NULL)
	{
		return false;
	}

	double firstDrawingPoint[2] = { 0.0, 0.0 };
	double secondDrawingPoint[2] = { 0.0, 0.0 };
	double mutableFirstPoint[3] = { firstPoint[0], firstPoint[1], firstPoint[2] };
	double mutableSecondPoint[3] = { secondPoint[0], secondPoint[1], secondPoint[2] };
	if (UF_VIEW_map_model_to_drawing(baseView->Tag(), mutableFirstPoint, firstDrawingPoint) != 0 ||
		UF_VIEW_map_model_to_drawing(baseView->Tag(), mutableSecondPoint, secondDrawingPoint) != 0)
	{
		return false;
	}

	return fabs(firstDrawingPoint[0] - secondDrawingPoint[0]) < tolerance &&
		fabs(firstDrawingPoint[1] - secondDrawingPoint[1]) < tolerance;
}

struct OuterRadiusFaceGroups
{
	std::vector<NXOpen::Face*> rightAngleFaces;
	std::vector<NXOpen::Face*> notRightAngleFaces;
	std::vector<NXOpen::Face*> straightAngleFaces;
};

static OuterRadiusFaceGroups ClassifyOuterRadiusFacesForView(
	NXOpen::Part* part,
	const std::vector<NXOpen::Face*>& outerRadiusFaces,
	NXOpen::Drawings::BaseView* baseView)
{
	OuterRadiusFaceGroups groups;
	if (part == NULL || baseView == NULL)
	{
		return groups;
	}

	for (size_t i = 0; i < outerRadiusFaces.size(); i++)
	{
		if (outerRadiusFaces[i] == NULL)
		{
			continue;
		}

		double point[3], dir[3], box[6], radius, radData;
		int type, normDir;
		UF_MODL_ask_face_data(outerRadiusFaces[i]->Tag(), &type, point, dir, box, &radius, &radData, &normDir);

		std::vector<NXOpen::Edge*> projectedLineEdges;
		std::vector<NXOpen::Edge*> outerEdges = outerRadiusFaces[i]->GetEdges();
		for (size_t edgeIndex = 0; edgeIndex < outerEdges.size(); edgeIndex++)
		{
			UF_EVAL_p_t evaluator;
			bool isLine = false;
			if (UF_EVAL_initialize(outerEdges[edgeIndex]->Tag(), &evaluator) != 0)
			{
				continue;
			}
			UF_EVAL_is_line(evaluator, &isLine);
			if (!isLine)
			{
				continue;
			}

			UF_EVAL_line_t lineCoords;
			UF_EVAL_ask_line(evaluator, &lineCoords);
			double startPoint[3] = { lineCoords.start[0], lineCoords.start[1], lineCoords.start[2] };
			double endPoint[3] = { lineCoords.end[0], lineCoords.end[1], lineCoords.end[2] };
			if (AreModelPointsCoincidentInDrawing(baseView, startPoint, endPoint, 0.01))
			{
				projectedLineEdges.push_back(outerEdges[edgeIndex]);
			}
		}

		if (projectedLineEdges.size() < 2 || projectedLineEdges[0] == NULL || projectedLineEdges[1] == NULL)
		{
			continue;
		}

		double projectedDistance = MeasureMinimumDistance(part, projectedLineEdges[0], projectedLineEdges[1]);
		if (fabs(projectedDistance - sqrt(2 * pow(radius, 2))) < 0.001)
		{
			groups.rightAngleFaces.push_back(outerRadiusFaces[i]);
		}
		else if (fabs(projectedDistance - radius * 2) > 0.01)
		{
			groups.notRightAngleFaces.push_back(outerRadiusFaces[i]);
		}
		else
		{
			groups.straightAngleFaces.push_back(outerRadiusFaces[i]);
		}
	}

	return groups;
}

static void CollectFirstCutDimensionFacesForView(
	NXOpen::Part* part,
	const std::vector<NXOpen::Face*>& firstCutRadiusFaces,
	const std::vector<NXOpen::Face*>& planarFaces,
	const std::vector<NXOpen::Face*>& excludedFaces,
	std::vector<NXOpen::Face*>& firstDimensionFaces)
{
	for (size_t i = 0; i < firstCutRadiusFaces.size(); i++)
	{
		if (i >= excludedFaces.size())
		{
			continue;
		}

		for (size_t j = 0; j < planarFaces.size(); j++)
		{
			double distance = MeasureMinimumDistance(part, planarFaces[j], firstCutRadiusFaces[i]);
			if (distance < 0.01 && planarFaces[j] != excludedFaces[i])
			{
				firstDimensionFaces.push_back(planarFaces[j]);
			}
		}
	}
}

static NXOpen::Point3d BuildOffsetOriginFromDrawingPoint(const double drawingPoint[2], double centerX, double centerY, double offset)
{
	NXOpen::Point3d originPoint(0.0, 0.0, 0.0);
	if (drawingPoint == NULL)
	{
		return originPoint;
	}

	originPoint.X = drawingPoint[0] >= centerX ? drawingPoint[0] + offset : drawingPoint[0] - offset;
	originPoint.Y = drawingPoint[1] >= centerY ? drawingPoint[1] + offset : drawingPoint[1] - offset;
	return originPoint;
}

static NXOpen::Point3d BuildOffsetOriginFromModelPoint(NXOpen::Drawings::BaseView* baseView, const double modelPoint[3], double centerX, double centerY, double offset)
{
	double drawingPoint[2] = { 0.0, 0.0 };
	if (baseView == NULL || modelPoint == NULL)
	{
		return NXOpen::Point3d(0.0, 0.0, 0.0);
	}

	double mutableModelPoint[3] = { modelPoint[0], modelPoint[1], modelPoint[2] };
	UF_VIEW_map_model_to_drawing(baseView->Tag(), mutableModelPoint, drawingPoint);
	return BuildOffsetOriginFromDrawingPoint(drawingPoint, centerX, centerY, offset);
}

