						double point1c[3], dir[3], box[6], radius1, rad_data;
						int type1, norm_dir;
						UF_MODL_ask_face_data(DuanMianRFace1[i]->Tag(), &type1, point1c, dir, box, &radius1, &rad_data, &norm_dir);

